      starterCode: "#include <stdio.h>\n\nint main(int argc, char *argv[]) {\n    if (argc < 2) {\n        fprintf(stderr, \"Usage: %s <file>\\n\", argv[0]);\n        return 1;\n    }\n    FILE *fp = fopen(argv[1], \"r\");\n    if (fp == NULL) {\n        perror(argv[1]);\n        return 2;\n    }\n\n    long bytes = 0;\n    int c;\n    // TODO: 写一个循环，逐字符读取直到文件末尾\n    //       每读到一个字符，就把计数器加一\n\n    printf(\"bytes: %ld\\n\", bytes);\n    fclose(fp);\n    return 0;\n}\n",
