      starterCode: "#include <stdio.h>\n\n/* TODO: 用 enum 定义设备的三个状态：STATE_IDLE / STATE_RUN / STATE_ERROR */\n\nint main(void) {\n    /* TODO: 声明一个当前状态变量 state，初始化为 STATE_IDLE */\n    /* TODO: 用 printf 打印 state 的数值 */\n    return 0;\n}\n",
